#include <stdio.h>
#include <stdint.h>

static int64_t modPow(int64_t a,int64_t e,int64_t mod){int64_t r=1%mod; a%=mod; while(e){if(e&1) r=(r*a)%mod; a=(a*a)%mod; e>>=1;}return r;}
static int64_t egcd(int64_t a,int64_t b,int64_t *x,int64_t *y){if(b==0){*x=1;*y=0;return a;}int64_t x1,y1;int64_t g=egcd(b,a%b,&x1,&y1);*x=y1;*y=x1-(a/b)*y1;return g;}
static int64_t modInv(int64_t a,int64_t mod){int64_t x,y;int64_t g=egcd(a,mod,&x,&y);if(g!=1) return -1; x%=mod; if(x<0) x+=mod; return x;}

int main(){int T; if(scanf("%d",&T)!=1) return 0; while(T--){int64_t n; int k; int64_t p; scanf("%lld %d %lld",&n,&k,&p);
    int m=k+2; // number of points = k+2
    int64_t y[m]; y[0]=0; for(int i=1;i<m;i++) y[i]=(y[i-1]+modPow(i,k,p))%p;
    if(n<=k+1){printf("%lld\n",y[n]); continue;}
    int64_t pre[m+1]; int64_t suf[m+1];
    pre[0]=1; for(int i=0;i<m;i++) pre[i+1]=(pre[i]*(((n - i)%p + p)%p))%p; // pre[i]=prod_{j=0}^{i-1}(n-j)
    suf[m]=1; for(int i=m-1;i>=0;i--) suf[i]=(suf[i+1]*(((n - i)%p + p)%p))%p; // suf[i]=prod_{j=i}^{m-1}(n-j)
    int64_t ans=0;
    for(int i=0;i<m;i++){
        int64_t num = (pre[i]*suf[i+1])%p; // numerator = product_{j!=i}(n-j)
        // denominator = i! * (m-1-i)! * (-1)^{m-1-i}
        int64_t den=1;
        int64_t fact=1; for(int j=1;j<=i;j++) fact=(fact*j)%p; // i!
        int64_t fact2=1; for(int j=1;j<=m-1-i;j++) fact2=(fact2*j)%p; // (m-1-i)!
        den = (fact*fact2)%p;
        if(((m-1-i)&1)) den = (p - den)%p; // apply (-1)^{m-1-i}
        int64_t inv = modInv(den,p);
        int64_t term = y[i]; term = (term * num)%p; term = (term * inv)%p;
        ans = (ans + term)%p;
    }
    printf("%lld\n",ans);
 }
 return 0; }
